mapper.select:
SELECT COUNT(1)
FROM log_login l
WHERE 1 = 1

      AND l.username LIKE CONCAT('%', #{query.username}, '%')


      AND l.success_flag = #{query.successFlag}


      AND l.ip LIKE CONCAT('%', #{query.ip}, '%')


      AND l.login_time  >=  #{query.startTime}


      AND l.login_time  <=  #{query.endTime}

SELECT id, user_id, username, success_flag, message, ip, user_agent, login_time
FROM log_login l
WHERE 1 = 1

      AND l.username LIKE CONCAT('%', #{query.username}, '%')


      AND l.success_flag = #{query.successFlag}


      AND l.ip LIKE CONCAT('%', #{query.ip}, '%')


      AND l.login_time  >=  #{query.startTime}


      AND l.login_time  <=  #{query.endTime}

ORDER BY l.login_time DESC, l.id DESC
LIMIT #{size} OFFSET #{offset}
